def is_numeric(x: Any) -> bool:
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def extract_stats_blob(entry: dict[str, Any]) -> dict[str, Any]:
    """Return the single nested stats dict (any key other than filename)."""
    blobs = [
        v
        for k, v in entry.items()
        if k != "filename" and isinstance(v, dict)
    ]
    if not blobs:
        return {}
    if len(blobs) > 1:
        merged: dict[str, Any] = {}
        for b in blobs:
            merged.update(b)
        return merged
    return blobs[0]


def load_by_filename(path: Path) -> dict[str, dict[str, Any]]:
    data = json.loads(path.read_text(encoding="utf-8"))
    out: dict[str, dict[str, Any]] = {}
    for entry in data.get("results", []):
        fn = entry.get("filename")
        if not fn:
            continue
        stats = extract_stats_blob(entry)
        if stats:
            out[str(fn)] = stats
    return out


def collect_numeric_series(
    by_file: dict[str, dict[str, Any]],
) -> dict[str, list[float]]:
    series: dict[str, list[float]] = {}
    for _fn, stats in sorted(by_file.items()):
        for key, val in stats.items():
            if not is_numeric(val):
                continue
            series.setdefault(key, []).append(float(val))
    return series


def summarize_series(values: list[float]) -> tuple[float, float, float, float]:
    if not values:
        return (float("nan"), float("nan"), float("nan"), float("nan"))
    s = sorted(values)
    return (
        min(s),
        max(s),
        statistics.fmean(s),
        statistics.median(s),
    )


def fmt_num(x: float, width: int = 12) -> str:
    if x != x:  # NaN
        return "N/A".rjust(width)
    if abs(x) >= 1e6 or (abs(x) < 1e-4 and x != 0.0):
        return f"{x:>{width}.6e}"
    return f"{x:>{width}.6f}".rstrip("0").rstrip(".").rjust(width)


def fmt_pct(x: float, width: int = 10) -> str:
    if x != x:
        return "N/A".rjust(width)
    return f"{x:>{width}.4f}"


def fmt_abs_total(x: float, width: int = 16) -> str:
    """Format summed absolute units (not percent); integers print without decimals."""
    if x != x:
        return "N/A".rjust(width)
    rx = round(x)
    if abs(x - rx) < 1e-6:
        return f"{int(rx):,}".rjust(width)
    s = f"{x:,.6f}".rstrip("0").rstrip(".")
    return s.rjust(width)


def mean_difference(
    control: dict[str, dict[str, Any]],
    variant: dict[str, dict[str, Any]],
    key: str,
) -> float:
    """Mean of (control - variant) over aligned numeric pairs."""
    vals: list[float] = []
    for fn, cstats in control.items():
        if fn not in variant:
            continue
        vstats = variant[fn]
        if key not in cstats or key not in vstats:
            continue
        cval, vval = cstats[key], vstats[key]
        if not is_numeric(cval) or not is_numeric(vval):
            continue
        vals.append(float(cval) - float(vval))
    if not vals:
        return float("nan")
    return statistics.fmean(vals)


def mean_nonnegative_percent_reduction(
    control: dict[str, dict[str, Any]],
    variant: dict[str, dict[str, Any]],
    key: str,
) -> tuple[float, int]:
    """
    Mean max(0, (control-variant)/control*100) and count of positive reductions.
    control==0 or missing/non-numeric pairs are skipped.
    """
    vals: list[float] = []
    n_positive = 0
    for fn, cstats in control.items():
        if fn not in variant:
            continue
        vstats = variant[fn]
        if key not in cstats or key not in vstats:
            continue
        cval, vval = cstats[key], vstats[key]
        if not is_numeric(cval) or not is_numeric(vval):
            continue
        cf, vf = float(cval), float(vval)
        if cf == 0.0:
            continue
        red_pct = max(0.0, (cf - vf) / cf * 100.0)
        vals.append(red_pct)
        if red_pct > 0.0:
            n_positive += 1
    if not vals:
        return (float("nan"), 0)
    return (statistics.fmean(vals), n_positive)


def _table_row_width(col_widths: list[int]) -> int:
    """Width of '| ... | ... |' row including outer pipes."""
    return 1 + sum(w + 3 for w in col_widths)


def _compute_column_widths(
    headers: list[str],
    rows: list[list[str]],
    max_width: int,
    min_col: int = 3,
) -> list[int]:
    n = len(headers)
    inner_budget = max_width - 1 - 3 * n
    if inner_budget < n:
        min_col = max(1, inner_budget // max(n, 1))

    raw: list[int] = []
    for j in range(n):
        m = len(headers[j])
        for row in rows:
            if j < len(row):
                m = max(m, len(str(row[j])))
        raw.append(max(m, min_col))

    total_raw = sum(raw)
    if total_raw <= inner_budget:
        widths = raw
    else:
        widths = [max(min_col, int(r * inner_budget / total_raw)) for r in raw]
        diff = inner_budget - sum(widths)
        while diff > 0:
            idx = max(range(n), key=lambda i: raw[i] - widths[i])
            widths[idx] += 1
            diff -= 1
        while diff < 0:
            idx = max(range(n), key=lambda i: widths[i])
            if widths[idx] > min_col:
                widths[idx] -= 1
                diff += 1
            else:
                break
    return widths


def _wrap_cell(text: str, width: int) -> list[str]:
    if width <= 0:
        return [textwrap.shorten(text, width=max(MAX_TABLE_WIDTH - 4, 8), placeholder="…")]
    lines = textwrap.wrap(
        text,
        width=width,
        break_long_words=True,
        break_on_hyphens=False,
    )
    return lines if lines else [""]


def _format_wrapped_physical_lines(
    cell_lines: list[list[str]],
    col_widths: list[int],
) -> list[str]:
    max_h = max((len(cl) for cl in cell_lines), default=1)
    out: list[str] = []
    for li in range(max_h):
        buf = "|"
        for j, w in enumerate(col_widths):
            chunk = cell_lines[j][li] if li < len(cell_lines[j]) else ""
            buf += f" {chunk:<{w}} |"
        out.append(buf)
    return out


def print_table(
    headers: list[str],
    rows: list[list[str]],
    title: str,
    max_width: int = MAX_TABLE_WIDTH,
) -> None:
    print()
    for title_line in textwrap.wrap(title, width=max_width, break_long_words=True) or [
        ""
    ]:
        print(title_line)

    str_rows: list[list[str]] = [[str(c) for c in row] for row in rows]
    col_widths = _compute_column_widths(headers, str_rows, max_width)
    # Hard cap: rounding bugs or tiny max_width must never exceed budget.
    while _table_row_width(col_widths) > max_width and max(col_widths) > 1:
        i = max(range(len(col_widths)), key=lambda k: col_widths[k])
        col_widths[i] -= 1

    def sep_line(char: str = "-") -> str:
        parts = ["+" + char * (w + 2) for w in col_widths]
        return "".join(parts) + "+"

    print(sep_line("="))
    hdr_cells = [_wrap_cell(headers[j], col_widths[j]) for j in range(len(headers))]
    for phys in _format_wrapped_physical_lines(hdr_cells, col_widths):
        print(phys)
    print(sep_line())
    for row in str_rows:
        padded = row + [""] * (len(headers) - len(row))
        cell_wrapped = [
            _wrap_cell(padded[j], col_widths[j]) for j in range(len(headers))
        ]
        for phys in _format_wrapped_physical_lines(cell_wrapped, col_widths):
            print(phys)
    print(sep_line())


def mean_percent_vs_control(
    control: dict[str, dict[str, Any]],
    variant: dict[str, dict[str, Any]],
    key: str,
) -> float:
    """Mean signed percent change: (variant - control) / control * 100, skipping control==0 or missing."""
    diffs: list[float] = []
    for fn, cstats in control.items():
        if fn not in variant:
            continue
        vstats = variant[fn]
        if key not in cstats or key not in vstats:
            continue
        cval, vval = cstats[key], vstats[key]
        if not is_numeric(cval) or not is_numeric(vval):
            continue
        cf, vf = float(cval), float(vval)
        if cf == 0.0:
            continue
        diffs.append((vf - cf) / cf * 100.0)
    if not diffs:
        return float("nan")
    return statistics.fmean(diffs)


def percent_reduction_subset_stats(
    control: dict[str, dict[str, Any]],
    variant: dict[str, dict[str, Any]],
    key: str,
) -> tuple[float, int]:
    """
    Mean (control-variant)/control*100 over benchmarks where that value is > 0, and the count of
    such benchmarks. control==0 pairs are skipped.
    """
    reductions: list[float] = []
    for fn, cstats in control.items():
        if fn not in variant:
            continue
        vstats = variant[fn]
        if key not in cstats or key not in vstats:
            continue
        cval, vval = cstats[key], vstats[key]
        if not is_numeric(cval) or not is_numeric(vval):
            continue
        cf, vf = float(cval), float(vval)
        if cf == 0.0:
            continue
        reduction_pct = (cf - vf) / cf * 100.0
        if reduction_pct > 0.0:
            reductions.append(reduction_pct)
    if not reductions:
        return (float("nan"), 0)
    return (statistics.fmean(reductions), len(reductions))


def count_timeouts_memouts(
    by_fn: dict[str, dict[str, Any]],
) -> dict[str, tuple[int, int]]:
    """
    Per benchmark row in by_fn, count timeout vs memout for egglog, gurobi encoding phase, and
    gurobi solver. Uses egglog-status; gurobi-status values containing 'encoding' count toward
    gurobi-encoding, otherwise toward gurobi (e.g. timeout, memout).
    """
    n_to: dict[str, int] = {k: 0 for k in TIMEOUT_MEMOUT_TOOL_KEYS}
    n_mo: dict[str, int] = {k: 0 for k in TIMEOUT_MEMOUT_TOOL_KEYS}
    for stats in by_fn.values():
        es = str(stats.get("egglog-status", "")).lower()
        if "memout" in es:
            n_mo["egglog"] += 1
        elif "timeout" in es:
            n_to["egglog"] += 1

        gs = str(stats.get("gurobi-status", "")).lower()
        if "timeout" not in gs and "memout" not in gs:
            continue
        key = "gurobi-encoding" if "encoding" in gs else "gurobi"
        if "memout" in gs:
            n_mo[key] += 1
        elif "timeout" in gs:
            n_to[key] += 1
    return {k: (n_to[k], n_mo[k]) for k in TIMEOUT_MEMOUT_TOOL_KEYS}


def row_has_timeout_or_memout(stats: dict[str, Any]) -> bool:
    """True if egglog-status or gurobi-status mentions timeout or memout (same idea as Par-2)."""
    return any(
        "timeout" in str(stats.get(k, "")).lower()
        or "memout" in str(stats.get(k, "")).lower()
        for k in PAR2_STATUS_KEYS
    )


def small_egraph_timeout_subset_stats(
    by_fn: dict[str, dict[str, Any]],
    *,
    enodes_eclasses_lt: float = SMALL_EGRAPH_ENODES_ECLASSES_LT,
) -> tuple[int, int, int]:
    """
    Return (n_total_rows, n_small, n_small_with_timeout_or_memout).

    n_total_rows: len(by_fn) (benchmark rows in this results file).
    n_small: rows with numeric num-enodes and num-eclasses both strictly less than enodes_eclasses_lt.
    n_small_with_timeout_or_memout: subset of n_small where row_has_timeout_or_memout is true.
    """
    n_total = len(by_fn)
    n_small = 0
    n_small_to_mo = 0
    for stats in by_fn.values():
        ne = stats.get("num-enodes")
        nc = stats.get("num-eclasses")
        if not is_numeric(ne) or not is_numeric(nc):
            continue
        assert isinstance(ne, (int, float)) and isinstance(nc, (int, float))
        if float(ne) >= enodes_eclasses_lt or float(nc) >= enodes_eclasses_lt:
            continue
        n_small += 1
        if row_has_timeout_or_memout(stats):
            n_small_to_mo += 1
    return (n_total, n_small, n_small_to_mo)


def mean_metric(by_fn: dict[str, dict[str, Any]], key: str) -> float:
    """Arithmetic mean of key over benchmarks where the value is numeric; NaN if none."""
    vals: list[float] = []
    for stats in by_fn.values():
        v = stats.get(key)
        if not is_numeric(v):
            continue
        assert isinstance(v, (int, float))
        vals.append(float(v))
    if not vals:
        return float("nan")
    return statistics.fmean(vals)


def median_metric(by_fn: dict[str, dict[str, Any]], key: str) -> float:
    """Median of key over benchmarks where the value is numeric; NaN if none."""
    vals: list[float] = []
    for stats in by_fn.values():
        v = stats.get(key)
        if not is_numeric(v):
            continue
        assert isinstance(v, (int, float))
        vals.append(float(v))
    if not vals:
        return float("nan")
    return statistics.median(vals)


def mean_sum_metrics(
    by_fn: dict[str, dict[str, Any]],
    keys: tuple[str, ...],
    *,
    allow_negative: bool = True,
) -> float:
    """
    Mean of per-row sum over rows where all keys are numeric; NaN if none.

    When allow_negative is False, rows with any negative value are skipped.
    This is used to ignore sentinel values such as -1 for unavailable timings.
    """
    vals: list[float] = []
    for stats in by_fn.values():
        parts: list[float] = []
        ok = True
        for k in keys:
            v = stats.get(k)
            if not is_numeric(v):
                ok = False
                break
            assert isinstance(v, (int, float))
            vf = float(v)
            if not allow_negative and vf < 0.0:
                ok = False
                break
            parts.append(vf)
        if ok:
            vals.append(sum(parts))
    if not vals:
        return float("nan")
    return statistics.fmean(vals)


def par2_score(
    by_fn: dict[str, dict[str, Any]],
    time_keys: tuple[str, ...],
    status_keys: tuple[str, ...],
    timeout_seconds: float,
) -> float:
    """
    Mean Par-2 runtime score over benchmark rows.

    Successful rows use the summed runtime over time_keys. Rows with timeout/memout status are
    penalized as 2 * timeout_seconds. Rows with missing or negative successful timings are skipped.
    """
    vals: list[float] = []
    penalty = 2.0 * timeout_seconds
    for stats in by_fn.values():
        failed = any(
            "timeout" in str(stats.get(k, "")).lower()
            or "memout" in str(stats.get(k, "")).lower()
            for k in status_keys
        )
        if failed:
            vals.append(penalty)
            continue

        parts: list[float] = []
        ok = True
        for k in time_keys:
            v = stats.get(k)
            if not is_numeric(v):
                ok = False
                break
            assert isinstance(v, (int, float))
            vf = float(v)
            if vf < 0.0:
                ok = False
                break
            parts.append(vf)
        if ok:
            vals.append(sum(parts))
    if not vals:
        return float("nan")
    return statistics.fmean(vals)


def sum_absolute_reduction(
    control: dict[str, dict[str, Any]],
    variant: dict[str, dict[str, Any]],
    key: str,
) -> float:
    """
    Sum of (control - variant) over aligned benchmarks where variant < control (strictly).
    Non-numeric or missing keys are skipped.
    """
    total = 0.0
    for fn, cstats in control.items():
        if fn not in variant:
            continue
        vstats = variant[fn]
        if key not in cstats or key not in vstats:
            continue
        cval, vval = cstats[key], vstats[key]
        if not is_numeric(cval) or not is_numeric(vval):
            continue
        cf, vf = float(cval), float(vval)
        if cf > vf:
            total += cf - vf
    return total


def overall_reduction_amount_stats(
    control: dict[str, dict[str, Any]],
    variants: list[dict[str, dict[str, Any]]],
    key: str,
) -> tuple[float, float, int, int]:
    """
    Aggregate absolute reduction amounts across all variant files and aligned benchmarks.

    Returns:
      - mean reduction amount over all comparisons: max(0, control-variant)
      - mean reduction amount over only positive reductions (>0)
      - count of all valid comparisons
      - count of positive-reduction comparisons
    """
    reductions_all: list[float] = []
    reductions_pos: list[float] = []
    for variant in variants:
        for fn, cstats in control.items():
            if fn not in variant:
                continue
            vstats = variant[fn]
            if key not in cstats or key not in vstats:
                continue
            cval, vval = cstats[key], vstats[key]
            if not is_numeric(cval) or not is_numeric(vval):
                continue
            cf, vf = float(cval), float(vval)
            red_amt = max(0.0, cf - vf)
            reductions_all.append(red_amt)
            if red_amt > 0.0:
                reductions_pos.append(red_amt)

    mean_all = statistics.fmean(reductions_all) if reductions_all else float("nan")
    mean_pos = statistics.fmean(reductions_pos) if reductions_pos else float("nan")
    return (mean_all, mean_pos, len(reductions_all), len(reductions_pos))


def short_benchmark_path(filename: str) -> str:
    marker = "/benchmarks/"
    if marker in filename:
        return "benchmarks/" + filename.split(marker, 1)[1]
    return filename


def strict_scq_winner_stats(
    run_maps: dict[str, dict[str, dict[str, Any]]],
    basenames: tuple[str, ...] = STRICT_WINNER_RESULT_FILES,
) -> tuple[list[list[str]], dict[str, dict[str, Any]]]:
    """
    Count formulas where one run file has strictly lower scq than all other run files.

    Also returns the largest-margin winner per run file, where margin is the gap
    between the winning scq and the next-lowest scq among the other runs.
    """
    available = [basename for basename in basenames if basename in run_maps]
    if len(available) < 2:
        return ([], {})

    common_filenames = set(run_maps[available[0]])
    for basename in available[1:]:
        common_filenames &= set(run_maps[basename])

    counts = {basename: 0 for basename in available}
    extremes: dict[str, dict[str, Any]] = {}

    for filename in sorted(common_filenames):
        values: dict[str, float] = {}
        for basename in available:
            scq = run_maps[basename][filename].get("scq")
            if not is_numeric(scq):
                break
            assert isinstance(scq, (int, float))
            values[basename] = float(scq)
        if len(values) != len(available):
            continue

        best_scq = min(values.values())
        winners = [basename for basename, scq in values.items() if scq == best_scq]
        if len(winners) != 1:
            continue

        winner = winners[0]
        counts[winner] += 1
        next_best = min(scq for basename, scq in values.items() if basename != winner)
        margin = next_best - best_scq
        candidate = {
            "filename": filename,
            "formula": str(run_maps[winner][filename].get("formula", "")),
            "margin": margin,
            "scq": best_scq,
            "values": values,
        }
        current = extremes.get(winner)
        if (
            current is None
            or margin > float(current["margin"])
            or (
                margin == float(current["margin"])
                and (
                    best_scq < float(current["scq"])
                    or (
                        best_scq == float(current["scq"])
                        and filename < str(current["filename"])
                    )
                )
            )
        ):
            extremes[winner] = candidate

    rows: list[list[str]] = []
    for basename in available:
        extreme = extremes.get(basename)
        if extreme is None:
            rows.append([basename, str(counts[basename]), "N/A", "N/A", "N/A"])
            continue
        values = extreme["values"]
        assert isinstance(values, dict)
        rows.append(
            [
                basename,
                str(counts[basename]),
                fmt_abs_total(float(extreme["scq"])).strip(),
                fmt_abs_total(float(extreme["margin"])).strip(),
                ", ".join(
                    f"{other}={fmt_abs_total(float(values[other])).strip()}"
                    for other in available
                ),
            ]
        )

    return (rows, extremes)


def print_extreme_strict_scq_formulas(
    extremes: dict[str, dict[str, Any]],
    basenames: tuple[str, ...],
) -> None:
    print()
    print("Most extreme strict SCQ winner formulas by run file")
    print("=" * 52)
    for basename in basenames:
        extreme = extremes.get(basename)
        if extreme is None:
            print(f"{basename}: no strict SCQ winner found")
            continue

        values = extreme["values"]
        assert isinstance(values, dict)
        print()
        print(basename)
        print(f"  filename: {short_benchmark_path(str(extreme['filename']))}")
        print(f"  winning scq: {fmt_abs_total(float(extreme['scq'])).strip()}")
        print(f"  margin to next best: {fmt_abs_total(float(extreme['margin'])).strip()}")
        print(
            "  all scq: "
            + ", ".join(
                f"{other}={fmt_abs_total(float(values[other])).strip()}"
                for other in basenames
                if other in values
            )
        )
        print("  formula:")
        for line in textwrap.wrap(
            str(extreme["formula"]),
            width=MAX_TABLE_WIDTH - 4,
            break_long_words=True,
            break_on_hyphens=False,
        ) or [""]:
            print(f"    {line}")


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    results_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else script_dir.parent / "results"
    results_dir = results_dir.resolve()

    if not results_dir.is_dir():
        print(f"Not a directory: {results_dir}", file=sys.stderr)
        return 1

    control_path = results_dir / "control.json"
    if not control_path.is_file():
        print(f"Missing {control_path}", file=sys.stderr)
        return 1

    vb_written = write_virtual_best_per_metric(results_dir)
    if not vb_written:
        print(
            "Warning: metric-specific virtual-best files not regenerated (see virtual_best messages); "
            "using existing files if present.",
            file=sys.stderr,
        )
    vb_out = write_virtual_best(results_dir)
    if vb_out is None:
        print(
            f"Warning: {VIRTUAL_BEST_BASENAME} not regenerated; using existing file if present.",
            file=sys.stderr,
        )

    control_map = load_by_filename(control_path)
    virtual_best_by_metric: dict[str, dict[str, dict[str, Any]]] = {}
    for metric, basename in VIRTUAL_BEST_METRIC_TO_BASENAME.items():
        path = results_dir / basename
        if path.is_file():
            virtual_best_by_metric[metric] = load_by_filename(path)

    def metric_variant_map(
        basename: str,
        metric: str,
        fallback: dict[str, dict[str, Any]],
    ) -> dict[str, dict[str, Any]]:
        if basename != VIRTUAL_BEST_BASENAME:
            return fallback
        # For virtual_best row, use the per-metric virtual-best file when available.
        return virtual_best_by_metric.get(metric, fallback)

    for basename in RESULT_JSON_FILES:
        path = results_dir / basename
        if not path.is_file():
            print(f"Warning: missing results file, skipping: {path}", file=sys.stderr)
            continue
        by_fn = load_by_filename(path)
        series = collect_numeric_series(by_fn)
        rows: list[list[str]] = []
        for metric in sorted(series.keys()):
            mn, mx, avg, med = summarize_series(series[metric])
            rows.append(
                [
                    metric,
                    fmt_num(mn),
                    fmt_num(mx),
                    fmt_num(avg),
                    fmt_num(med),
                ]
            )
        print_table(
            ["metric", "min", "max", "avg", "median"],
            rows,
            f"Numeric summary: {path.name} — {results_dir}",
        )

    # Percent vs control for variant JSON only (same order as RESULT_JSON_FILES minus control).
    compare_signed_rows: list[list[str]] = []
    compare_red_rows: list[list[str]] = []
    compare_variant_maps: list[dict[str, dict[str, Any]]] = []
    compare_variant_map_by_name: dict[str, dict[str, Any]] = {}
    variant_basenames: list[str] = []
    for basename in RESULT_JSON_FILES:
        if basename == "control.json":
            continue
        path = results_dir / basename
        if not path.is_file():
            print(f"Warning: missing results file, skipping compare: {path}", file=sys.stderr)
            continue
        var_map = load_by_filename(path)
        variant_basenames.append(basename)
        compare_variant_maps.append(var_map)
        compare_variant_map_by_name[basename] = var_map
        row_s = [path.name]
        row_r = [path.name]
        for key in COMPARE_KEYS:
            key_map = metric_variant_map(basename, key, var_map)
            row_s.append(fmt_pct(mean_percent_vs_control(control_map, key_map, key)))
            red_avg, red_n = percent_reduction_subset_stats(control_map, key_map, key)
            row_r.append(fmt_pct(red_avg))
            if key == "scq":
                row_r.append(str(red_n))
        compare_signed_rows.append(row_s)
        compare_red_rows.append(row_r)

    if compare_signed_rows:
        signed_headers = list(COMPARE_KEYS)
        print_table(
            ["file"] + signed_headers,
            compare_signed_rows,
            f"Mean signed percent difference vs control.json: (variant-control)/control*100 "
            f"(control==0 omitted per metric) — {results_dir}",
        )
        red_headers: list[str] = []
        for k in COMPARE_KEYS:
            red_headers.append(k)
            if k == "scq":
                red_headers.append("n red>0")
        print_table(
            ["file"] + red_headers,
            compare_red_rows,
            f"Mean percent reduction vs control.json: (control-variant)/control*100 averaged only "
            f"over benchmarks with reduction > 0; n red>0 counts scq reductions only "
            f"(control==0 omitted) — {results_dir}",
        )
        overall_rows: list[list[str]] = []
        for basename, var_map in zip(variant_basenames, compare_variant_maps):
            overall_row: list[str] = [basename]
            for key in COMPARE_KEYS:
                key_map = metric_variant_map(basename, key, var_map)
                mean_all, mean_pos, _n_all, _n_pos = overall_reduction_amount_stats(
                    control_map, [key_map], key
                )
                overall_row.append(
                    f"{fmt_abs_total(mean_all).strip()} ({fmt_abs_total(mean_pos).strip()})"
                )
            overall_rows.append(overall_row)
        print_table(
            ["file"] + list(COMPARE_KEYS),
            overall_rows,
            f"Average amount reduced vs control.json (one row per variant file, columns are "
            f"metrics): each cell is avg max(0, control-variant) in raw units over aligned "
            f"benchmark rows, with positive-only average (>0 reductions) in parentheses; "
            f"non-numeric pairs skipped — {results_dir}",
        )

        strict_rows, strict_extremes = strict_scq_winner_stats(
            compare_variant_map_by_name
        )
        if strict_rows:
            print_table(
                ["file", "strict scq wins", "extreme scq", "extreme margin", "extreme all scq"],
                strict_rows,
                f"Strict SCQ winners across source run files only: a row wins a benchmark when its "
                f"scq is lower than all other source run files for the same filename. Extreme margin "
                f"is the selected run's largest gap to the next-lowest scq — {results_dir}",
            )
            print_extreme_strict_scq_formulas(
                strict_extremes,
                tuple(
                    b
                    for b in STRICT_WINNER_RESULT_FILES
                    if b in compare_variant_map_by_name
                ),
            )

    timeout_rows: list[list[str]] = []
    for basename in RESULT_JSON_FILES:
        path = results_dir / basename
        if not path.is_file():
            print(f"Warning: missing results file, skipping timeout/memout: {path}", file=sys.stderr)
            continue
        if basename == VIRTUAL_BEST_BASENAME:
            timeout_rows.append(["VB", "N/A", "N/A", "N/A"])
            continue
        by_fn = load_by_filename(path)
        counts = count_timeouts_memouts(by_fn)
        egglog_avg_time = mean_sum_metrics(
            by_fn,
            ("egglog-encoding-time", "egglog-solver-time"),
            allow_negative=False,
        )
        gurobi_avg_time = mean_sum_metrics(
            by_fn,
            ("gurobi-encoding-time", "gurobi-solving-time"),
            allow_negative=False,
        )
        total_par2_score = par2_score(
            by_fn,
            (
                "egglog-encoding-time",
                "egglog-solver-time",
                "gurobi-encoding-time",
                "gurobi-solving-time",
            ),
            ("egglog-status", "gurobi-status"),
            PAR2_TIMEOUT_SECONDS,
        )

        egglog_to, egglog_mo = counts["egglog"]
        ge_to, ge_mo = counts["gurobi-encoding"]
        g_to, g_mo = counts["gurobi"]
        gurobi_to, gurobi_mo = (ge_to + g_to, ge_mo + g_mo)

        timeout_rows.append(
            [
                path.name,
                f"{fmt_num(egglog_avg_time).strip()} ({egglog_to},{egglog_mo})",
                f"{fmt_num(gurobi_avg_time).strip()} ({gurobi_to},{gurobi_mo})",
                fmt_num(total_par2_score).strip(),
            ]
        )

    if timeout_rows:
        tm_headers = [
            "file",
            "egglog avg time (TO,MO)",
            "gurobi avg time (TO,MO)",
            "Par-2 score",
        ]
        print_table(
            tm_headers,
            timeout_rows,
            f"Average runtime and timeout/memout counts per results file (per benchmark row): "
            f"egglog avg time is egglog-encoding-time + egglog-solver-time; gurobi avg time is "
            f"gurobi-encoding-time + gurobi-solving-time. (TO,MO) are timeout/memout counts from "
            f"egglog-status and gurobi-status (encoding_* rolled into gurobi totals). Par-2 score "
            f"uses total egglog+gurobi runtime for successful rows and 2*{PAR2_TIMEOUT_SECONDS:g}s "
            f"for timeout/memout rows — {results_dir}",
        )

    egraph_rows: list[list[str]] = []
    egraph_summary_by_name: dict[str, tuple[float, float, float, float]] = {}
    for basename in RESULT_JSON_FILES:
        path = results_dir / basename
        if not path.is_file():
            print(
                f"Warning: missing results file, skipping e-graph averages: {path}",
                file=sys.stderr,
            )
            continue
        by_fn = load_by_filename(path)
        avg_enodes = mean_metric(by_fn, "num-enodes")
        med_enodes = median_metric(by_fn, "num-enodes")
        avg_eclasses = mean_metric(by_fn, "num-eclasses")
        med_eclasses = median_metric(by_fn, "num-eclasses")
        egraph_summary_by_name[basename] = (
            avg_enodes,
            med_enodes,
            avg_eclasses,
            med_eclasses,
        )
        egraph_rows.append(
            [path.name]
            + [fmt_num(avg_enodes), fmt_num(avg_eclasses)]
        )

    if egraph_rows:
        print_table(
            ["file", "avg num-enodes", "avg num-eclasses"],
            egraph_rows,
            f"Average egglog e-graph size per results file: mean of num-enodes and num-eclasses "
            f"over benchmark rows with numeric values (missing/non-numeric omitted) — {results_dir}",
        )

    thr = int(SMALL_EGRAPH_ENODES_ECLASSES_LT)
    n_total_all = 0
    n_small_all = 0
    n_small_to_mo_all = 0
    n_loaded_strict_files = 0
    for basename in STRICT_WINNER_RESULT_FILES:
        path = results_dir / basename
        if not path.is_file():
            print(
                f"Warning: missing results file, skipping small e-graph aggregate: {path}",
                file=sys.stderr,
            )
            continue
        by_fn = load_by_filename(path)
        nt, ns, ntm = small_egraph_timeout_subset_stats(by_fn)
        n_total_all += nt
        n_small_all += ns
        n_small_to_mo_all += ntm
        n_loaded_strict_files += 1

    if n_total_all > 0:
        pct_of_all = 100.0 * n_small_all / n_total_all
        pct_small_failed = (
            100.0 * n_small_to_mo_all / n_small_all if n_small_all > 0 else float("nan")
        )
        print_table(
            [
                f"n total rows ({n_loaded_strict_files} run file(s))",
                f"n (num-enodes<{thr} & num-eclasses<{thr})",
                "% of all rows",
                "n TO/MO in subset",
                "% of subset w/ TO/MO",
            ],
            [
                [
                    f"{n_total_all:,}",
                    f"{n_small_all:,}",
                    fmt_pct(pct_of_all).strip(),
                    f"{n_small_to_mo_all:,}",
                    fmt_pct(pct_small_failed).strip(),
                ]
            ],
            f"Aggregate over the run JSON files present among {', '.join(STRICT_WINNER_RESULT_FILES)} "
            f"(not control or virtual-best): summed benchmark rows across each loaded file "
            f"({n_loaded_strict_files} file(s) this run). "
            f"Small-graph rows require numeric num-enodes and num-eclasses both strictly under {thr}. "
            f"The '% of all rows' column is 100*n_small/n_total. TO/MO: substring timeout/memout on "
            f"egglog-status and gurobi-status (Par-2 convention). The '% of subset w/ TO/MO' column "
            f"is among small-graph rows only — {results_dir}",
        )

    return 0


if __name__ == "__main__":
    raise SystemExit(main())
